import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../components/Navbar';

const API = '';

const nama = 'Hagia Sofiana';
const tentang =
  'Full Stack Developer specializing in modern web and mobile development. Proficient in PHP, Laravel, JavaScript, React, Python, Java, and MySQL, with a passion for building scalable applications, writing clean code, and continuously exploring new technologies.';
const skills = ['HTML', 'CSS', 'JavaScript', 'PHP', 'MySQL', 'Python', 'Bootstrap', 'Java', 'React', 'Vite'];

export default function Home() {
  const [recentProjects, setRecentProjects] = useState([]);
  const [totalProject, setTotalProject] = useState(0);
  const cardRefs = useRef([]);

  useEffect(() => {
    fetch(`${API}/api/projects/recent`)
      .then((r) => r.json())
      .then(setRecentProjects)
      .catch(console.error);

    fetch(`${API}/api/projects/count`)
      .then((r) => r.json())
      .then((d) => setTotalProject(d.total))
      .catch(console.error);
  }, []);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry, i) => {
          if (entry.isIntersecting) {
            setTimeout(() => {
              entry.target.style.opacity = '1';
              entry.target.style.transform = 'translateY(0)';
            }, i * 100);
          }
        });
      },
      { threshold: 0.1, rootMargin: '0px 0px -50px 0px' }
    );
    cardRefs.current.forEach((el) => {
      if (el) {
        el.style.opacity = '0';
        el.style.transform = 'translateY(30px)';
        el.style.transition = 'all 0.7s cubic-bezier(0.34,1.56,0.64,1)';
        observer.observe(el);
      }
    });
    return () => observer.disconnect();
  }, [recentProjects]);

  return (
    <>
      <style>{`
        :root {
          --pink-1:#ff6b9d;--pink-2:#ff4d7a;--pink-3:#ff2d5a;--pink-4:#ff8aae;--pink-5:#ffb3c8;
          --gradient-main:linear-gradient(135deg,#ff6b9d 0%,#ff4d7a 40%,#ff2d5a 80%,#ff6b9d 100%);
          --gradient-soft:linear-gradient(135deg,#ff8aae 0%,#ffb3c8 100%);
          --gradient-glass:linear-gradient(135deg,rgba(255,107,157,0.08),rgba(255,45,90,0.04));
          --text-dark:#1a1a2e;--text-gray:#6b7280;
          --glass-bg:rgba(255,255,255,0.82);--glass-border:rgba(255,255,255,0.5);
          --glass-shadow:0 8px 32px rgba(255,75,122,0.10);
          --radius-lg:28px;--radius-md:18px;
          --transition:all 0.5s cubic-bezier(0.34,1.56,0.64,1);
        }
        body { background: linear-gradient(160deg,#fff5f7 0%,#ffe8ee 30%,#ffdce4 60%,#fff0f3 100%); color:var(--text-dark); min-height:100vh; }
        @keyframes floatOrb{0%,100%{transform:translate(0,0)scale(1)}25%{transform:translate(40px,-50px)scale(1.15)}50%{transform:translate(-25px,25px)scale(0.85)}75%{transform:translate(50px,30px)scale(1.1)}}
        @keyframes gradientMove{0%,100%{background-position:0% 50%}50%{background-position:100% 50%}}
        @keyframes shimmer{0%,100%{background-position:0% 50%}50%{background-position:100% 50%}}
        @keyframes pulseBadge{0%,100%{transform:scale(1)}50%{transform:scale(1.03)}}
        @keyframes fadeInUp{from{opacity:0;transform:translateY(50px)scale(0.96)}to{opacity:1;transform:translateY(0)scale(1)}}
        @keyframes floatProfile{0%,100%{transform:translateY(0)rotate(0)}33%{transform:translateY(-6px)rotate(-0.5deg)}66%{transform:translateY(3px)rotate(0.5deg)}}
        @keyframes morphShape{
          0%{border-radius:30% 70% 45% 55% / 55% 40% 60% 45%}
          20%{border-radius:50% 50% 35% 65% / 65% 35% 65% 35%}
          40%{border-radius:40% 60% 55% 45% / 45% 55% 40% 60%}
          60%{border-radius:55% 45% 40% 60% / 40% 60% 50% 50%}
          80%{border-radius:35% 65% 50% 50% / 55% 40% 60% 45%}
          100%{border-radius:30% 70% 45% 55% / 55% 40% 60% 45%}
        }
        @keyframes spinRing{to{transform:rotate(360deg)}}
        @keyframes pulseGlowRing{0%,100%{transform:scale(1);opacity:0.6}50%{transform:scale(1.12);opacity:1}}
        @keyframes pulseBg{0%,100%{transform:scale(1);opacity:0.5}50%{transform:scale(1.3);opacity:1}}
        @keyframes expandLine{from{width:0;opacity:0}to{width:24px;opacity:1}}

        .bg-orb{position:absolute;border-radius:50%;filter:blur(100px);animation:floatOrb 25s ease-in-out infinite}
        .bg-orb:nth-child(1){width:600px;height:600px;background:#ff6b9d;top:-250px;right:-150px;opacity:0.12}
        .bg-orb:nth-child(2){width:450px;height:450px;background:#ff8aae;bottom:-150px;left:-120px;animation-delay:-8s;opacity:0.15}
        .bg-orb:nth-child(3){width:350px;height:350px;background:#ffb3c8;top:50%;left:40%;animation-delay:-16s;opacity:0.1}

        .hero-section{padding:0.5rem 0 2rem;animation:fadeInUp 1s cubic-bezier(0.34,1.56,0.64,1)}
        .hero-glass{
          background:var(--glass-bg);backdrop-filter:blur(24px) saturate(200%);
          border-radius:var(--radius-lg);border:1px solid var(--glass-border);
          box-shadow:var(--glass-shadow);padding:1rem 1.5rem;
          position:relative;overflow:hidden;transition:var(--transition);
        }
        .hero-glass:hover{box-shadow:0 16px 56px rgba(255,75,122,0.14);transform:translateY(-3px)}

        .profile-wrapper{position:relative;display:inline-block;animation:floatProfile 6s ease-in-out infinite}
        .profile-image{
          width:280px;height:280px;object-fit:cover;
          border:4px solid rgba(255,107,157,0.2);
          box-shadow:0 16px 48px rgba(255,75,122,0.18);
          transition:var(--transition);
          background:linear-gradient(135deg,#fff5f7,#ffe8ee);
          animation:morphShape 10s ease-in-out infinite;
          position:relative;z-index:2;
        }
        .profile-image:hover{transform:scale(1.04) rotate(2deg);box-shadow:0 20px 56px rgba(255,75,122,0.25)}
        .profile-ring{
          position:absolute;inset:-14px;
          border:2.5px solid transparent;
          background:var(--gradient-main) border-box;
          -webkit-mask:linear-gradient(#fff 0 0) padding-box,linear-gradient(#fff 0 0);
          -webkit-mask-composite:xor;mask-composite:exclude;
          animation:spinRing 14s linear infinite;z-index:1;
          animation:morphShape 10s ease-in-out infinite,spinRing 14s linear infinite;
        }
        .profile-glow{
          position:absolute;inset:-25px;
          background:radial-gradient(circle at center,rgba(255,107,157,0.12),transparent 70%);
          filter:blur(40px);
          animation:pulseGlowRing 4s ease-in-out infinite;z-index:0;
        }

        .hero-badge{
          display:inline-flex;align-items:center;gap:0.6rem;
          background:rgba(255,75,122,0.08);color:#ff4d7a;
          padding:0.4rem 1.4rem;border-radius:50px;font-size:0.82rem;font-weight:600;
          margin-bottom:1.2rem;border:1px solid rgba(255,75,122,0.1);
          animation:pulseBadge 2.5s ease-in-out infinite;
        }
        .hero-title{font-size:3.5rem;font-weight:900;line-height:1.08;margin-bottom:0.75rem;letter-spacing:-1.5px}
        .hero-title .highlight{
          background:var(--gradient-main);-webkit-background-clip:text;
          -webkit-text-fill-color:transparent;background-clip:text;
          background-size:200% 200%;animation:gradientMove 4s ease-in-out infinite;position:relative;
        }
        .hero-subtitle{font-size:1.05rem;color:var(--text-gray);max-width:480px;margin-bottom:1.8rem;line-height:1.8}
        .hero-actions{display:flex;flex-wrap:wrap;gap:1rem;margin-bottom:1.8rem}

        .btn-primary-custom{
          background:var(--gradient-main);color:white;border:none;
          padding:0.85rem 2.6rem;border-radius:50px;font-weight:700;font-size:0.98rem;
          transition:var(--transition);box-shadow:0 4px 20px rgba(255,75,122,0.3);
          text-decoration:none;display:inline-flex;align-items:center;gap:0.6rem;
          background-size:200% 200%;animation:shimmer 3s ease-in-out infinite;
          position:relative;overflow:hidden;
        }
        .btn-primary-custom:hover{transform:translateY(-4px)scale(1.03);box-shadow:0 8px 32px rgba(255,75,122,0.4);color:white}
        .btn-outline-custom{
          background:transparent;color:var(--text-dark);
          border:2px solid rgba(255,75,122,0.12);
          padding:0.85rem 2.6rem;border-radius:50px;font-weight:600;font-size:0.98rem;
          transition:var(--transition);text-decoration:none;
          display:inline-flex;align-items:center;gap:0.6rem;
        }
        .btn-outline-custom:hover{background:rgba(255,75,122,0.04);border-color:rgba(255,75,122,0.2);color:var(--text-dark)}

        .social-links{display:flex;gap:0.75rem}
        .social-link{
          width:42px;height:42px;border-radius:14px;
          background:var(--glass-bg);border:1px solid rgba(255,107,157,0.15);
          display:inline-flex;align-items:center;justify-content:center;
          color:var(--text-gray);text-decoration:none;font-size:1.1rem;
          transition:var(--transition);box-shadow:0 2px 8px rgba(255,75,122,0.06);
        }
        .social-link:hover{
          background:var(--gradient-main);color:white;
          transform:translateY(-4px)rotate(-5deg);
          box-shadow:0 6px 20px rgba(255,75,122,0.3);border-color:transparent;
        }

        .skills-section{padding:3rem 0;background:transparent}
        .section-title{font-size:2.2rem;font-weight:800;color:var(--text-dark);margin-bottom:0.5rem;letter-spacing:-0.5px}
        .gradient-text{
          background:var(--gradient-main);-webkit-background-clip:text;
          -webkit-text-fill-color:transparent;background-clip:text;
          background-size:200% 200%;animation:gradientMove 4s ease-in-out infinite;
        }
        .section-divider{
          width:60px;height:4px;margin:0.75rem auto 1rem;
          background:var(--gradient-main);border-radius:4px;
        }
        .section-subtitle{color:var(--text-gray);font-size:1rem;margin-bottom:2rem}

        .skill-tag{
          display:inline-flex;align-items:center;gap:0.5rem;
          background:var(--glass-bg);border:1px solid rgba(255,107,157,0.12);
          padding:0.5rem 1.4rem;border-radius:50px;margin:0.3rem;
          font-size:0.88rem;font-weight:600;color:var(--text-dark);
          transition:var(--transition);box-shadow:0 2px 8px rgba(255,75,122,0.06);
          cursor:default;
        }
        .skill-tag i{color:#ff4d7a;font-size:0.75rem}
        .skill-tag:hover{background:var(--gradient-main);color:white;transform:translateY(-3px)scale(1.05);box-shadow:0 6px 20px rgba(255,75,122,0.25);border-color:transparent}
        .skill-tag:hover i{color:white}

        .project-card{
          background:var(--glass-bg);backdrop-filter:blur(20px);
          border-radius:var(--radius-md);border:1px solid rgba(255,107,157,0.1);
          box-shadow:0 4px 16px rgba(255,75,122,0.08);
          overflow:hidden;transition:var(--transition);height:100%;
        }
        .project-card:hover{transform:translateY(-8px);box-shadow:0 16px 48px rgba(255,75,122,0.18);border-color:rgba(255,107,157,0.2)}
        .project-card-img{width:100%;height:200px;object-fit:cover;display:block}
        .project-card-body{padding:1.5rem}
        .project-card-title{font-size:1.05rem;font-weight:700;color:var(--text-dark);margin-bottom:0.5rem}
        .project-card-desc{font-size:0.88rem;color:var(--text-gray);margin-bottom:1rem;display:-webkit-box;-webkit-line-clamp:3;-webkit-box-orient:vertical;overflow:hidden}
        .project-tech{display:flex;flex-wrap:wrap;gap:0.35rem;margin-bottom:1rem}
        .project-tech-badge{background:rgba(255,75,122,0.08);color:#ff4d7a;padding:0.25rem 0.75rem;border-radius:50px;font-size:0.75rem;font-weight:600;border:1px solid rgba(255,75,122,0.1)}
        .project-card-links{display:flex;gap:0.75rem}
        .project-card-links a{
          display:inline-flex;align-items:center;gap:0.4rem;
          font-size:0.82rem;font-weight:600;color:var(--text-gray);
          text-decoration:none;padding:0.4rem 1rem;
          border-radius:50px;border:1px solid rgba(0,0,0,0.08);
          transition:var(--transition);
        }
        .project-card-links a:hover{background:var(--gradient-main);color:white;border-color:transparent;transform:translateY(-2px)}

        .stat-item{
          background:var(--glass-bg);backdrop-filter:blur(20px);
          border-radius:var(--radius-md);border:1px solid rgba(255,107,157,0.1);
          box-shadow:0 4px 16px rgba(255,75,122,0.08);
          padding:1.5rem 2rem;text-align:center;transition:var(--transition);
        }
        .stat-item:hover{transform:translateY(-4px);box-shadow:0 8px 28px rgba(255,75,122,0.14)}
        .stat-number{font-size:2.5rem;font-weight:900;line-height:1;margin-bottom:0.25rem}
        .stat-label{font-size:0.85rem;color:var(--text-gray);font-weight:500}

        .footer-glass{
          background:var(--glass-bg);backdrop-filter:blur(20px);
          border-top:1px solid rgba(255,107,157,0.1);
          padding:1.5rem 0;margin-top:4rem;
        }
        .footer-text{font-size:0.9rem;color:var(--text-gray)}
        .heart{color:#ff4d7a;animation:pulseBadge 1.5s ease-in-out infinite;display:inline-block}
        .code-icon{color:#ff4d7a}

        @media(max-width:768px){
          .hero-title{font-size:2.5rem}
          .profile-image{width:220px;height:220px}
          .profile-wrapper{transform:none}
        }
      `}</style>

      {/* Animated background */}
      <div style={{ position: 'fixed', inset: 0, zIndex: 0, overflow: 'hidden', pointerEvents: 'none' }}>
        <div className="bg-orb"></div>
        <div className="bg-orb"></div>
        <div className="bg-orb"></div>
      </div>

      <Navbar />

      <div style={{ position: 'relative', zIndex: 1, paddingTop: '100px' }}>
        {/* Hero */}
        <section className="hero-section">
          <div className="container">
            <div className="hero-glass">
              <div className="row align-items-center">
                {/* Profile Image */}
                <div className="col-lg-5 order-1 order-lg-1 text-center mb-4 mb-lg-0">
                  <div className="profile-wrapper">
                    <div className="profile-glow"></div>
                    <div className="profile-ring"></div>
                    <div className="profile-image" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      <i className="fas fa-user" style={{ fontSize: '5rem', color: '#ff4d7a', opacity: 0.4 }}></i>
                    </div>
                  </div>
                </div>
                {/* Content */}
                <div className="col-lg-7 order-2 order-lg-2">
                  <div className="hero-content">
                    <div className="hero-badge">
                      <i className="fas fa-graduation-cap"></i>
                      Rekayasa Perangkat Lunak
                    </div>
                    <h1 className="hero-title">
                      Hi, i'm<br />
                      <span className="highlight">Hagia Sofiana</span>
                    </h1>
                    <p className="hero-subtitle">{tentang}</p>
                    <div className="hero-actions">
                      <Link to="/project" className="btn-primary-custom">
                        <i className="fas fa-folder-open"></i>Lihat Project
                      </Link>
                      <a href="#skills" className="btn-outline-custom">
                        <span><i className="fas fa-code me-2"></i>Skill Saya</span>
                      </a>
                    </div>
                    <div className="social-links">
                      <a href="https://github.com/ann4yaa" className="social-link" target="_blank" rel="noreferrer"><i className="fab fa-github"></i></a>
                      <a href="https://www.linkedin.com/in/hagia-sofiana" className="social-link" target="_blank" rel="noreferrer"><i className="fab fa-linkedin-in"></i></a>
                      <a href="https://www.instagram.com/ann4yaa_" className="social-link" target="_blank" rel="noreferrer"><i className="fab fa-instagram"></i></a>
                      <a href="https://www.threads.com/@ann4yaa_" className="social-link" target="_blank" rel="noreferrer"><i className="fab fa-threads"></i></a>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* Stats */}
        <section style={{ padding: '2rem 0' }}>
          <div className="container">
            <div className="row g-3 justify-content-center">
              <div className="col-6 col-md-3">
                <div className="stat-item" ref={(el) => { cardRefs.current[0] = el; }}>
                  <div className="stat-number gradient-text">{totalProject}+</div>
                  <div className="stat-label">Total Project</div>
                </div>
              </div>
              <div className="col-6 col-md-3">
                <div className="stat-item" ref={(el) => { cardRefs.current[1] = el; }}>
                  <div className="stat-number gradient-text">{skills.length}+</div>
                  <div className="stat-label">Teknologi</div>
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* Skills */}
        <section className="skills-section" id="skills">
          <div className="container">
            <div className="text-center">
              <h2 className="section-title">Teknologi yang <span className="gradient-text">Dikuasai</span></h2>
              <div className="section-divider"></div>
              <p className="section-subtitle">Stack teknologi yang saya gunakan dalam pengembangan web</p>
            </div>
            <div className="text-center">
              {skills.map((skill, i) => (
                <span className="skill-tag" key={i} ref={(el) => { cardRefs.current[i + 2] = el; }}>
                  <i className="fas fa-check-circle"></i>
                  <span>{skill}</span>
                </span>
              ))}
            </div>
          </div>
        </section>

        {/* Recent Projects */}
        <section style={{ padding: '3.5rem 0' }}>
          <div className="container">
            <div className="text-center">
              <h2 className="section-title">Project <span className="gradient-text">Terbaru</span></h2>
              <div className="section-divider"></div>
              <p className="section-subtitle">Beberapa project yang telah saya kerjakan</p>
            </div>

            {recentProjects.length > 0 ? (
              <>
                <div className="row g-4">
                  {recentProjects.map((project, i) => {
                    const teknologiList = project.teknologi ? project.teknologi.split('|') : [];
                    return (
                      <div className="col-md-4" key={project.id}>
                        <div className="project-card h-100" ref={(el) => { cardRefs.current[i + 12] = el; }}>
                          {project.gambar ? (
                            <img src={`/uploads/${project.gambar}`} alt={project.nama_project} className="project-card-img" />
                          ) : (
                            <div className="project-card-img d-flex align-items-center justify-content-center"
                              style={{ background: 'linear-gradient(135deg,#f5e5cd 0%,#fff8ed 100%)' }}>
                              <i className="fas fa-image" style={{ fontSize: '3rem', color: '#8a4b2a' }}></i>
                            </div>
                          )}
                          <div className="project-card-body">
                            <h5 className="project-card-title">{project.nama_project}</h5>
                            <p className="project-card-desc">{project.deskripsi}</p>
                            <div className="project-tech">
                              {teknologiList.slice(0, 3).map((t, j) => (
                                <span className="project-tech-badge" key={j}>{t}</span>
                              ))}
                              {teknologiList.length > 3 && (
                                <span className="project-tech-badge">+{teknologiList.length - 3}</span>
                              )}
                            </div>
                            <div className="project-card-links">
                              {project.github && (
                                <a href={project.github} target="_blank" rel="noreferrer">
                                  <i className="fab fa-github me-1"></i><span>GitHub</span>
                                </a>
                              )}
                              {project.demo && (
                                <a href={project.demo} target="_blank" rel="noreferrer">
                                  <i className="fas fa-external-link-alt me-1"></i><span>Demo</span>
                                </a>
                              )}
                            </div>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
                <div className="text-center mt-4">
                  <Link to="/project" className="btn-primary-custom">
